// Player (Pac-Man) class

import { PELLET_PAUSE_FRAMES, ENERGIZER_PAUSE_FRAMES } from '../constants'
import { Direction, Position, SpeedPattern } from '../types'
import { setDirFromEnum, isNextTileFloor } from './Direction'
import { Actor } from './Actor'

/**
 * Player class - controllable Pac-Man character
 */
export class Player extends Actor {
	// Next direction to move
	nextDir: Position = { x: 0, y: 0 }
	nextDirEnum: Direction = Direction.LEFT

	// Input direction from user
	inputDirEnum: Direction | undefined = undefined

	// Movement state
	stopped: boolean = false

	// Eating pause frames
	eatPauseFramesLeft: number = 0

	// Last meal position (for audio)
	lastMeal: Position = { x: -1, y: -1 }

	// AI control flag
	ai: boolean = false
	invincible: boolean = false

	// Energizer state reference
	private energizerActive: boolean = false
	private level: number = 1

	constructor() {
		super()
		this.frames = 0
	}

	/**
	 * Set the current level for speed calculations
	 */
	setLevel(level: number): void {
		this.level = level
	}

	/**
	 * Set energizer active state
	 */
	setEnergizerActive(active: boolean): void {
		this.energizerActive = active
	}

	/**
	 * Reset player state for new level or restart
	 */
	reset(): void {
		this.setNextDir(this.startDirEnum)
		this.stopped = false
		this.inputDirEnum = undefined
		this.eatPauseFramesLeft = 0
		this.lastMeal = { x: -1, y: -1 }

		super.reset()
	}

	/**
	 * Set next direction
	 */
	setNextDir(nextDirEnum: Direction): void {
		setDirFromEnum(this.nextDir, nextDirEnum)
		this.nextDirEnum = nextDirEnum
	}

	/**
	 * Get number of steps to move this frame
	 */
	getNumSteps(): number {
		const pattern = this.energizerActive
			? SpeedPattern.PACMAN_FRIGHT
			: SpeedPattern.PACMAN
		return this.getStepSizeFromTable(this.level, pattern)
	}

	/**
	 * Get animation frame from step count
	 */
	getStepFrame(steps?: number): number {
		const s = steps ?? this.steps
		return Math.floor(s / 2) % 4
	}

	/**
	 * Get animation frame for rendering
	 */
	getAnimFrame(frame?: number): number {
		let f = frame ?? this.getStepFrame()
		// Classic Pac-Man animation: 0, 1, 2, 1 pattern
		if (f === 3) f = 1
		return f
	}

	/**
	 * Set input direction from user
	 */
	setInputDir(dirEnum: Direction): void {
		this.inputDirEnum = dirEnum
	}

	/**
	 * Clear input direction
	 */
	clearInputDir(dirEnum?: Direction): void {
		if (dirEnum === undefined || this.inputDirEnum === dirEnum) {
			this.inputDirEnum = undefined
		}
	}

	/**
	 * Move forward one step
	 */
	step(): number {
		if (!this.map) {
			this.setPos(this.pixel.x + this.dir.x, this.pixel.y + this.dir.y)
			return 1
		}

		// Identify axes of motion
		const a = this.dir.x !== 0 ? 'x' : 'y' // axis of motion
		const b = this.dir.x !== 0 ? 'y' : 'x' // perpendicular axis

		// Don't proceed past middle of tile if facing a wall
		const isFloor = isNextTileFloor(this.tile, this.dir, (x, y) =>
			this.map!.isFloorTile(x, y)
		)
		this.stopped = this.stopped || (this.distToMid[a] === 0 && !isFloor)

		if (!this.stopped) {
			// Move in direction of travel
			this.pixel[a] += this.dir[a]

			// Drift toward center of track (cornering)
			const sign = (x: number) => (x < 0 ? -1 : x > 0 ? 1 : 0)
			this.pixel[b] += sign(this.distToMid[b])
		}

		this.commitPos()
		return this.stopped ? 0 : 1
	}

	/**
	 * Determine direction
	 */
	steer(): void {
		if (!this.map) return

		if (this.inputDirEnum === undefined) {
			if (this.stopped) {
				this.setDir(this.nextDirEnum)
			}
		} else {
			// Determine if input direction is open
			const inputDir = { x: 0, y: 0 }
			setDirFromEnum(inputDir, this.inputDirEnum)
			const inputDirOpen = isNextTileFloor(this.tile, inputDir, (x, y) =>
				this.map!.isFloorTile(x, y)
			)

			if (inputDirOpen) {
				this.setDir(this.inputDirEnum)
				this.setNextDir(this.inputDirEnum)
				this.stopped = false
			} else {
				if (!this.stopped) {
					this.setNextDir(this.inputDirEnum)
				}
			}
		}
	}

	/**
	 * Update player for this substep
	 */
	update(substep: number): void {
		const numSteps = this.getNumSteps()
		if (substep >= numSteps) return

		// Skip frames for eating pause
		if (this.eatPauseFramesLeft > 0) {
			if (substep === numSteps - 1) {
				this.eatPauseFramesLeft--
			}
			return
		}

		// Call parent update
		super.update(substep)
	}

	/**
	 * Handle eating a pellet or energizer
	 * Returns the tile character that was eaten ('.' or 'o'), or null
	 */
	checkEating(): string | null {
		if (!this.map) return null

		const t = this.map.getTile(this.tile.x, this.tile.y)
		if (t === '.' || t === 'o') {
			this.lastMeal.x = this.tile.x
			this.lastMeal.y = this.tile.y

			// Apply eating pause
			this.eatPauseFramesLeft =
				t === '.' ? PELLET_PAUSE_FRAMES : ENERGIZER_PAUSE_FRAMES

			// Mark as eaten
			this.map.onDotEat(this.tile.x, this.tile.y)

			return t
		}

		return null
	}
}
