// Input handling hook for Pac-Man

import { useEffect, useCallback, useRef } from 'react'
import { Direction } from '../types'

interface UseInputOptions {
	onDirectionChange: (direction: Direction) => void
	onPause?: () => void
	onInteract?: () => void
	enabled: boolean
}

/**
 * Hook for handling keyboard and touch input
 */
export function useInput({
	onDirectionChange,
	onPause,
	onInteract,
	enabled,
}: UseInputOptions) {
	const touchStartRef = useRef<{ x: number; y: number } | null>(null)

	// Handle keyboard input
	const handleKeyDown = useCallback(
		(e: KeyboardEvent) => {
			if (!enabled) return

			// Trigger interaction callback (e.g., for audio init)
			onInteract?.()

			switch (e.key) {
				case 'ArrowUp':
				case 'w':
				case 'W':
					e.preventDefault()
					onDirectionChange(Direction.UP)
					break
				case 'ArrowDown':
				case 's':
				case 'S':
					e.preventDefault()
					onDirectionChange(Direction.DOWN)
					break
				case 'ArrowLeft':
				case 'a':
				case 'A':
					e.preventDefault()
					onDirectionChange(Direction.LEFT)
					break
				case 'ArrowRight':
				case 'd':
				case 'D':
					e.preventDefault()
					onDirectionChange(Direction.RIGHT)
					break
				case ' ':
				case 'Escape':
				case 'p':
				case 'P':
					e.preventDefault()
					onPause?.()
					break
			}
		},
		[onDirectionChange, onPause, onInteract, enabled]
	)

	// Handle touch start
	const handleTouchStart = useCallback(
		(e: TouchEvent) => {
			if (!enabled) return
			// Trigger interaction callback (e.g., for audio init)
			onInteract?.()
			const touch = e.touches[0]
			touchStartRef.current = { x: touch.clientX, y: touch.clientY }
		},
		[enabled, onInteract]
	)

	// Handle touch end (swipe detection)
	const handleTouchEnd = useCallback(
		(e: TouchEvent) => {
			if (!enabled || !touchStartRef.current) return

			const touch = e.changedTouches[0]
			const dx = touch.clientX - touchStartRef.current.x
			const dy = touch.clientY - touchStartRef.current.y
			const minSwipeDistance = 30

			// Determine swipe direction
			if (Math.abs(dx) > Math.abs(dy)) {
				// Horizontal swipe
				if (Math.abs(dx) > minSwipeDistance) {
					onDirectionChange(dx > 0 ? Direction.RIGHT : Direction.LEFT)
				}
			} else {
				// Vertical swipe
				if (Math.abs(dy) > minSwipeDistance) {
					onDirectionChange(dy > 0 ? Direction.DOWN : Direction.UP)
				}
			}

			touchStartRef.current = null
		},
		[onDirectionChange, enabled]
	)

	// Set up event listeners
	useEffect(() => {
		window.addEventListener('keydown', handleKeyDown)
		window.addEventListener('touchstart', handleTouchStart, { passive: true })
		window.addEventListener('touchend', handleTouchEnd)

		return () => {
			window.removeEventListener('keydown', handleKeyDown)
			window.removeEventListener('touchstart', handleTouchStart)
			window.removeEventListener('touchend', handleTouchEnd)
		}
	}, [handleKeyDown, handleTouchStart, handleTouchEnd])
}

/**
 * D-pad button handler for mobile controls
 */
export function useDPadInput(
	onDirectionChange: (direction: Direction) => void
) {
	const handleUp = useCallback(
		() => onDirectionChange(Direction.UP),
		[onDirectionChange]
	)
	const handleDown = useCallback(
		() => onDirectionChange(Direction.DOWN),
		[onDirectionChange]
	)
	const handleLeft = useCallback(
		() => onDirectionChange(Direction.LEFT),
		[onDirectionChange]
	)
	const handleRight = useCallback(
		() => onDirectionChange(Direction.RIGHT),
		[onDirectionChange]
	)

	return {
		handleUp,
		handleDown,
		handleLeft,
		handleRight,
	}
}
