// Ghost class for Pac-Man enemies

import { MID_TILE } from '../constants'
import {
	Direction,
	GhostMode,
	GhostCommand,
	SpeedPattern,
	OpenTiles,
	TilePosition,
} from '../types'
import { rotateAboutFace, getTurnClosestToTarget } from './Direction'
import { Actor } from './Actor'
import type { GameMap } from './Map'
import type { Player } from './Player'

/**
 * Ghost class - enemy AI characters
 */
export class Ghost extends Actor {
	// Ghost mode
	mode: GhostMode = GhostMode.OUTSIDE
	startMode: GhostMode = GhostMode.OUTSIDE
	arriveHomeMode: GhostMode = GhostMode.LEAVING_HOME

	// State flags
	scared: boolean = false
	sigReverse: boolean = false
	sigLeaveHome: boolean = false

	// Face direction (eyeball direction)
	faceDirEnum: Direction = Direction.LEFT

	// Elroy mode (Blinky speed-up)
	elroy: number = 0

	// Visual properties
	color: string = '#ff0000'
	cornerTile: TilePosition = { x: 0, y: 0 }

	// Reference to player for targeting
	private player: Player | null = null

	// Reference to commander for scatter/chase state
	private getCommand: () => GhostCommand = () => GhostCommand.SCATTER

	// Level for speed calculations
	private level: number = 1

	constructor(color: string = '#ff0000') {
		super()
		this.color = color
		this.faceDirEnum = this.dirEnum
	}

	/**
	 * Set references needed for ghost behavior
	 */
	setReferences(
		map: GameMap,
		player: Player,
		getCommand: () => GhostCommand,
		level: number
	): void {
		this.map = map
		this.player = player
		this.getCommand = getCommand
		this.level = level
	}

	/**
	 * Set level for speed calculations
	 */
	setLevel(level: number): void {
		this.level = level
	}

	/**
	 * Reset ghost state for new level or restart
	 */
	reset(): void {
		this.sigReverse = false
		this.sigLeaveHome = false
		this.mode = this.startMode
		this.scared = false
		this.elroy = 0

		super.reset()

		this.faceDirEnum = this.dirEnum
	}

	/**
	 * Check if ghost slows down in tunnel
	 */
	isSlowInTunnel(): boolean {
		return true // Original Pac-Man always slows in tunnel
	}

	/**
	 * Get number of steps to move this frame
	 */
	getNumSteps(): number {
		if (!this.map) return 1

		// Going home or entering home - fast speed
		if (
			this.mode === GhostMode.GOING_HOME ||
			this.mode === GhostMode.ENTERING_HOME
		) {
			return 2
		}

		// Leaving or pacing home - tunnel speed at level 1
		if (
			this.mode === GhostMode.LEAVING_HOME ||
			this.mode === GhostMode.PACING_HOME
		) {
			return this.getStepSizeFromTable(1, SpeedPattern.GHOST_TUNNEL)
		}

		// Check for tunnel
		if (
			this.map.isTunnelTile(this.tile.x, this.tile.y) &&
			this.isSlowInTunnel()
		) {
			return this.getStepSizeFromTable(this.level, SpeedPattern.GHOST_TUNNEL)
		}

		// Check for frightened
		if (this.scared) {
			return this.getStepSizeFromTable(this.level, SpeedPattern.GHOST_FRIGHT)
		}

		// Check for Elroy mode
		if (this.elroy === 1) {
			return this.getStepSizeFromTable(this.level, SpeedPattern.ELROY1)
		}
		if (this.elroy === 2) {
			return this.getStepSizeFromTable(this.level, SpeedPattern.ELROY2)
		}

		return this.getStepSizeFromTable(this.level, SpeedPattern.GHOST)
	}

	/**
	 * Get animation frame
	 */
	getAnimFrame(frames?: number): number {
		const f = frames ?? this.frames
		return Math.floor(f / 8) % 2 // Toggle every 8 ticks
	}

	/**
	 * Signal ghost to reverse direction
	 */
	reverse(): void {
		this.sigReverse = true
	}

	/**
	 * Signal ghost to go home (after being eaten)
	 */
	goHome(): void {
		this.mode = GhostMode.GOING_HOME
	}

	/**
	 * Signal ghost to leave home
	 */
	leaveHome(): void {
		this.sigLeaveHome = true
	}

	/**
	 * Called when pacman eats an energizer
	 */
	onEnergized(): void {
		this.reverse()

		// Only scare if not already going home
		if (
			this.mode !== GhostMode.GOING_HOME &&
			this.mode !== GhostMode.ENTERING_HOME
		) {
			this.scared = true
			this.targetting = undefined
		}
	}

	/**
	 * Called when this ghost gets eaten
	 */
	onEaten(): void {
		this.goHome()
		this.scared = false
	}

	/**
	 * Move forward one pixel
	 */
	step(): number {
		this.setPos(this.pixel.x + this.dir.x, this.pixel.y + this.dir.y)
		return 1
	}

	/**
	 * Ghost home-specific path steering
	 */
	homeSteer(): void {
		if (!this.map) return

		switch (this.mode) {
			case GhostMode.GOING_HOME:
				// At the doormat
				if (
					this.tile.x === this.map.doorTile.x &&
					this.tile.y === this.map.doorTile.y
				) {
					this.faceDirEnum = Direction.DOWN
					this.targetting = undefined

					// Walk to door or go through if there
					if (this.pixel.x === this.map.doorPixel.x) {
						this.mode = GhostMode.ENTERING_HOME
						this.setDir(Direction.DOWN)
						this.faceDirEnum = this.dirEnum
					} else {
						this.setDir(Direction.RIGHT)
						this.faceDirEnum = this.dirEnum
					}
				}
				break

			case GhostMode.ENTERING_HOME:
				if (this.pixel.y === this.map.homeBottomPixel) {
					// Revive if reached seat
					if (this.pixel.x === this.startPixel.x) {
						this.setDir(Direction.UP)
						this.mode = this.arriveHomeMode
					} else {
						// Sidestep to seat
						this.setDir(
							this.startPixel.x < this.pixel.x
								? Direction.LEFT
								: Direction.RIGHT
						)
					}
					this.faceDirEnum = this.dirEnum
				}
				break

			case GhostMode.PACING_HOME:
				if (this.sigLeaveHome) {
					this.sigLeaveHome = false
					this.mode = GhostMode.LEAVING_HOME

					if (this.pixel.x === this.map.doorPixel.x) {
						this.setDir(Direction.UP)
					} else {
						this.setDir(
							this.pixel.x < this.map.doorPixel.x
								? Direction.RIGHT
								: Direction.LEFT
						)
					}
				} else {
					// Pace back and forth
					if (this.pixel.y === this.map.homeTopPixel) {
						this.setDir(Direction.DOWN)
					} else if (this.pixel.y === this.map.homeBottomPixel) {
						this.setDir(Direction.UP)
					}
				}
				this.faceDirEnum = this.dirEnum
				break

			case GhostMode.LEAVING_HOME:
				if (this.pixel.x === this.map.doorPixel.x) {
					// Reached door
					if (this.pixel.y === this.map.doorPixel.y) {
						this.mode = GhostMode.OUTSIDE
						this.setDir(Direction.LEFT) // Always turn left at door
					} else {
						this.setDir(Direction.UP)
					}
					this.faceDirEnum = this.dirEnum
				}
				break
		}
	}

	/**
	 * Get open tiles for pathfinding
	 */
	getOpenTiles(tile: TilePosition, dirEnum: Direction): OpenTiles {
		if (!this.map) {
			return {
				[Direction.UP]: false,
				[Direction.LEFT]: false,
				[Direction.DOWN]: false,
				[Direction.RIGHT]: false,
			}
		}

		const openTiles: OpenTiles = {
			[Direction.UP]: this.map.isFloorTile(tile.x, tile.y - 1),
			[Direction.RIGHT]: this.map.isFloorTile(tile.x + 1, tile.y),
			[Direction.DOWN]: this.map.isFloorTile(tile.x, tile.y + 1),
			[Direction.LEFT]: this.map.isFloorTile(tile.x - 1, tile.y),
		}

		// Count open tiles
		let numOpen = 0
		for (let i = 0; i < 4; i++) {
			if (openTiles[i as Direction]) numOpen++
		}

		// Close passage behind ghost if there are other openings
		// (Ghosts can't reverse except on mode change)
		const oppDirEnum = rotateAboutFace(dirEnum)
		if (numOpen > 1) {
			openTiles[oppDirEnum] = false
		}

		return openTiles
	}

	/**
	 * Get target tile for chase mode
	 * Override in subclasses for different ghost behaviors
	 */
	getTargetTile(): TilePosition {
		// Default: target player directly (Blinky behavior)
		if (this.player) {
			return { x: this.player.tile.x, y: this.player.tile.y }
		}
		return { x: 0, y: 0 }
	}

	/**
	 * Set target based on current mode
	 */
	setTarget(): void {
		this.targetTile = this.getTargetTile()
		this.targetting = 'pacman'
	}

	/**
	 * Determine direction
	 */
	steer(): void {
		if (!this.map) return

		// Handle home-specific steering
		this.homeSteer()

		const oppDirEnum = rotateAboutFace(this.dirEnum)

		// Only execute targeting logic if outside or going home
		if (this.mode !== GhostMode.OUTSIDE && this.mode !== GhostMode.GOING_HOME) {
			this.targetting = undefined
			return
		}

		// At mid-tile - update movement direction
		if (this.distToMid.x === 0 && this.distToMid.y === 0) {
			// Trigger reversal
			if (this.sigReverse) {
				this.faceDirEnum = oppDirEnum
				this.sigReverse = false
			}

			// Commit previous direction
			this.setDir(this.faceDirEnum)
		}
		// Just passed mid-tile - update face direction
		else if (
			(this.dirEnum === Direction.RIGHT &&
				this.tilePixel.x === MID_TILE.x + 1) ||
			(this.dirEnum === Direction.LEFT &&
				this.tilePixel.x === MID_TILE.x - 1) ||
			(this.dirEnum === Direction.UP && this.tilePixel.y === MID_TILE.y - 1) ||
			(this.dirEnum === Direction.DOWN && this.tilePixel.y === MID_TILE.y + 1)
		) {
			// Get next tile
			const nextTile = {
				x: this.tile.x + this.dir.x,
				y: this.tile.y + this.dir.y,
			}

			// Get open tiles around next tile
			const openTiles = this.getOpenTiles(nextTile, this.dirEnum)

			let dirEnum: Direction

			if (this.scared) {
				// Choose random direction when scared
				dirEnum = Math.floor(Math.random() * 4) as Direction
				while (!openTiles[dirEnum]) {
					dirEnum = ((dirEnum + 1) % 4) as Direction
				}
				this.targetting = undefined
			} else {
				// Set target
				if (this.mode === GhostMode.GOING_HOME) {
					// Target ghost door
					this.targetTile.x = this.map.doorTile.x
					this.targetTile.y = this.map.doorTile.y
				} else if (!this.elroy && this.getCommand() === GhostCommand.SCATTER) {
					// Target corner when scattering
					this.targetTile.x = this.cornerTile.x
					this.targetTile.y = this.cornerTile.y
					this.targetting = 'corner'
				} else {
					// Use custom targeting for chase mode
					this.setTarget()
				}

				// Apply map constraints (prevent up turn at certain tiles)
				if (this.mode !== GhostMode.GOING_HOME) {
					this.map.constrainGhostTurns(nextTile, openTiles)
				}

				// Choose direction that minimizes distance to target
				dirEnum = getTurnClosestToTarget(nextTile, this.targetTile, openTiles)
			}

			// Point eyeballs to determined direction
			this.faceDirEnum = dirEnum
		}
	}
}
