import React from 'react'
import type { ActivePowerUp } from '../types'
import { POWER_UP_CONFIG } from '../constants'

interface BreakoutHUDProps {
	score: number
	brokenBlocks: number
	totalBlocks: number
	activePowerUps: ActivePowerUp[]
	brandColor: string
}

export const BreakoutHUD: React.FC<BreakoutHUDProps> = ({
	score,
	brokenBlocks,
	totalBlocks,
	activePowerUps,
	brandColor,
}) => {
	return (
		<div
			className="game-breakout-hud"
			style={{ borderColor: `${brandColor}33` }}
		>
			{/* Score */}
			<div className="game-breakout-hud-item">
				<span className="game-breakout-hud-icon">&#x1FA99;</span>
				<div className="game-breakout-hud-col">
					<span className="game-breakout-hud-label">
						Puntos
					</span>
					<span className="game-breakout-hud-value">
						{score.toLocaleString()}
					</span>
				</div>
			</div>

			{/* Broken Blocks */}
			<div className="game-breakout-hud-item">
				<span className="game-breakout-hud-icon">&#x1F9F1;</span>
				<div className="game-breakout-hud-col">
					<span className="game-breakout-hud-label">
						Bloques
					</span>
					<span className="game-breakout-hud-value">
						{brokenBlocks}/{totalBlocks}
					</span>
				</div>
			</div>

			{/* Active Power-ups */}
			<div className="game-breakout-powerups">
				{activePowerUps.length > 0 ? (
					activePowerUps.map((powerUp, index) => {
						const config = POWER_UP_CONFIG[powerUp.type]
						const remaining = Math.max(
							0,
							Math.ceil((powerUp.endTime - Date.now()) / 1000)
						)
						return (
							<div
								key={index}
								className="game-breakout-powerup-badge"
								style={{ borderColor: config.color }}
							>
								<span className="game-breakout-powerup-icon">{config.label.split(' ')[0]}</span>
								<span className="game-breakout-powerup-timer">
									{remaining}s
								</span>
							</div>
						)
					})
				) : (
					<span className="game-breakout-powerup-empty">Sin power-ups</span>
				)}
			</div>
		</div>
	)
}
