import { useState } from 'react';
import { Translations } from '../../../../types/i18n';

interface NamePromptProps {
  onSave: (name: string) => void;
  onSkip: () => void;
  t: Translations;
}

export function NamePrompt({ onSave, onSkip, t }: NamePromptProps) {
  const [name, setName] = useState('');

  return (
    <div className="name-prompt">
      <p className="name-prompt-label">{t.games.newHighScore}</p>
      <input
        className="name-prompt-input"
        type="text"
        placeholder={t.games.enterName}
        value={name}
        onChange={(e) => setName(e.target.value)}
        maxLength={20}
        autoFocus
        onKeyDown={(e) => {
          if (e.key === 'Enter' && name.trim()) onSave(name.trim());
        }}
      />
      <div className="name-prompt-buttons">
        <button
          className="name-prompt-btn name-prompt-btn-save"
          onClick={() => name.trim() && onSave(name.trim())}
          disabled={!name.trim()}
        >
          {t.games.saveScore}
        </button>
        <button
          className="name-prompt-btn name-prompt-btn-skip"
          onClick={onSkip}
        >
          {t.games.skip}
        </button>
      </div>
    </div>
  );
}
