import type { RoadSegment, Car, Sprite } from '../types'
import { COLORS, SPRITES, ROAD } from '../constants'
import { MathUtils } from '../utils/math'

/**
 * Road generation and management system
 * Optimized for performance and memory usage
 */
export class RoadEngine {
	private segments: RoadSegment[] = []
	private segmentLength: number
	private rumbleLength: number
	private trackLength: number = 0
	private billboardPlacements: Map<string, number> = new Map()
	private billboardImpressions: Map<string, number> = new Map()
	private billboardInstances: Map<
		string,
		{ segmentIndex: number; offset: number; seenInLaps: Set<number> }[]
	> = new Map()
	private nextBillboardId: number = 0

	constructor(segmentLength: number = 200, rumbleLength: number = 3) {
		this.segmentLength = segmentLength
		this.rumbleLength = rumbleLength
	}

	/**
	 * Get all road segments
	 */
	getSegments(): RoadSegment[] {
		return this.segments
	}

	/**
	 * Get track length
	 */
	getTrackLength(): number {
		return this.trackLength
	}

	/**
	 * Get billboard placements count
	 */
	getBillboardPlacements(): Map<string, number> {
		return new Map(this.billboardPlacements)
	}

	/**
	 * Get billboard impressions count
	 */
	getBillboardImpressions(): Map<string, number> {
		return new Map(this.billboardImpressions)
	}

	/**
	 * Record billboard impression for a specific segment and offset in a specific lap
	 */
	recordBillboardImpression(
		segmentIndex: number,
		offset: number,
		billboardName: string,
		currentLap: number
	): void {
		const instances = this.billboardInstances.get(billboardName)
		if (!instances) return

		// Find the specific billboard instance at this segment and offset
		const instance = instances.find(
			inst =>
				inst.segmentIndex === segmentIndex &&
				Math.abs(inst.offset - offset) < 0.1 // Small tolerance for floating point comparison
		)

		if (instance && !instance.seenInLaps.has(currentLap)) {
			instance.seenInLaps.add(currentLap)
			const current = this.billboardImpressions.get(billboardName) || 0
			this.billboardImpressions.set(billboardName, current + 1)
		}
	}

	/**
	 * Get billboard statistics as an object
	 */
	getBillboardStats(totalLaps: number): {
		placements: Record<string, number>
		impressions: Record<string, number>
		maxPossibleImpressions: Record<string, number>
		trackLength: number
		totalSegments: number
		totalLaps: number
	} {
		const placements: Record<string, number> = {}
		const impressions: Record<string, number> = {}
		const maxPossibleImpressions: Record<string, number> = {}

		this.billboardPlacements.forEach((count, name) => {
			placements[name] = count
			maxPossibleImpressions[name] = count * totalLaps
		})

		this.billboardImpressions.forEach((count, name) => {
			impressions[name] = count
		})

		// Calculate a realistic track length in meters
		// Game units don't correspond to real meters, so we apply a scale factor
		// Adjusted for actual segment counts (typically 3000-6000 segments)
		// Target track lengths: 2-4 km for realistic racing circuits
		const realisticTrackLength = Math.round(this.segments.length * 0.65)

		return {
			placements,
			impressions,
			maxPossibleImpressions,
			trackLength: realisticTrackLength,
			totalSegments: this.segments.length,
			totalLaps,
		}
	}

	/**
	 * Find segment by Z position
	 */
	findSegment(z: number): RoadSegment {
		return this.segments[
			Math.floor(z / this.segmentLength) % this.segments.length
		]
	}

	/**
	 * Get last Y position
	 */
	private lastY(): number {
		return this.segments.length === 0
			? 0
			: this.segments[this.segments.length - 1].p2.world.y
	}

	/**
	 * Add a road segment
	 */
	private addSegment(curve: number, y: number): void {
		const n = this.segments.length
		this.segments.push({
			index: n,
			p1: {
				world: { y: this.lastY(), z: n * this.segmentLength },
				camera: { x: 0, y: 0, z: 0 },
				screen: { x: 0, y: 0, w: 0, scale: 0 },
			},
			p2: {
				world: { y: y, z: (n + 1) * this.segmentLength },
				camera: { x: 0, y: 0, z: 0 },
				screen: { x: 0, y: 0, w: 0, scale: 0 },
			},
			curve: curve,
			sprites: [],
			cars: [],
			color: Math.floor(n / this.rumbleLength) % 2 ? COLORS.DARK : COLORS.LIGHT,
		})
	}

	/**
	 * Add a sprite to a segment
	 */
	private addSprite(n: number, sprite: Sprite, offset: number): void {
		if (this.segments[n]) {
			const spriteInstance = { source: sprite, offset: offset }

			// If it's a billboard, track it with a unique ID
			const billboardName = this.getBillboardName(sprite)
			if (billboardName) {
				const billboardId = `${billboardName}_${this.nextBillboardId++}`
				// Store the billboard ID in the sprite instance for later reference
				;(spriteInstance as any).billboardId = billboardId

				// Track the instance
				if (!this.billboardInstances.has(billboardName)) {
					this.billboardInstances.set(billboardName, [])
				}
				this.billboardInstances.get(billboardName)!.push({
					segmentIndex: n,
					offset: offset,
					seenInLaps: new Set<number>(),
				})
			}

			this.segments[n].sprites.push(spriteInstance)
		}
	}

	/**
	 * Add a road section with easing
	 */
	private addRoad(
		enter: number,
		hold: number,
		leave: number,
		curve: number,
		y: number
	): void {
		const startY = this.lastY()
		const endY = startY + MathUtils.toInt(y, 0) * this.segmentLength
		const total = enter + hold + leave

		// Enter phase with easing
		for (let n = 0; n < enter; n++) {
			this.addSegment(
				MathUtils.easeIn(0, curve, n / enter),
				MathUtils.easeInOut(startY, endY, n / total)
			)
		}

		// Hold phase
		for (let n = 0; n < hold; n++) {
			this.addSegment(
				curve,
				MathUtils.easeInOut(startY, endY, (enter + n) / total)
			)
		}

		// Leave phase with easing
		for (let n = 0; n < leave; n++) {
			this.addSegment(
				MathUtils.easeInOut(curve, 0, n / leave),
				MathUtils.easeInOut(startY, endY, (enter + hold + n) / total)
			)
		}
	}

	/**
	 * Add straight road section
	 */
	private addStraight(num: number = ROAD.LENGTH.MEDIUM): void {
		this.addRoad(num, num, num, 0, 0)
	}

	/**
	 * Add hill section
	 */
	private addHill(
		num: number = ROAD.LENGTH.MEDIUM,
		height: number = ROAD.HILL.MEDIUM
	): void {
		this.addRoad(num, num, num, 0, height)
	}

	/**
	 * Add curve section
	 */
	private addCurve(
		num: number = ROAD.LENGTH.MEDIUM,
		curve: number = ROAD.CURVE.MEDIUM,
		height: number = ROAD.HILL.NONE
	): void {
		this.addRoad(num, num, num, curve, height)
	}

	/**
	 * Add rolling hills section
	 */
	private addLowRollingHills(
		num: number = ROAD.LENGTH.SHORT,
		height: number = ROAD.HILL.LOW
	): void {
		this.addRoad(num, num, num, 0, height / 2)
		this.addRoad(num, num, num, 0, -height)
		this.addRoad(num, num, num, ROAD.CURVE.EASY, height)
		this.addRoad(num, num, num, 0, 0)
		this.addRoad(num, num, num, -ROAD.CURVE.EASY, height / 2)
		this.addRoad(num, num, num, 0, 0)
	}

	/**
	 * Add S-curves section
	 */
	private addSCurves(): void {
		this.addRoad(
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			-ROAD.CURVE.EASY,
			ROAD.HILL.NONE
		)
		this.addRoad(
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.CURVE.MEDIUM,
			ROAD.HILL.MEDIUM
		)
		this.addRoad(
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.CURVE.EASY,
			-ROAD.HILL.LOW
		)
		this.addRoad(
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			-ROAD.CURVE.EASY,
			ROAD.HILL.MEDIUM
		)
		this.addRoad(
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			ROAD.LENGTH.MEDIUM,
			-ROAD.CURVE.MEDIUM,
			-ROAD.HILL.MEDIUM
		)
	}

	/**
	 * Add bumps section
	 */
	private addBumps(): void {
		this.addRoad(10, 10, 10, 0, 5)
		this.addRoad(10, 10, 10, 0, -2)
		this.addRoad(10, 10, 10, 0, -5)
		this.addRoad(10, 10, 10, 0, 8)
		this.addRoad(10, 10, 10, 0, 5)
		this.addRoad(10, 10, 10, 0, -7)
		this.addRoad(10, 10, 10, 0, 5)
		this.addRoad(10, 10, 10, 0, -2)
	}

	/**
	 * Add downhill to end section
	 */
	private addDownhillToEnd(num: number = 200): void {
		this.addRoad(
			num,
			num,
			num,
			-ROAD.CURVE.EASY,
			-this.lastY() / this.segmentLength
		)
	}

	/**
	 * Reset and rebuild road
	 */
	reset(track: number = 0, playerZ: number): void {
		this.segments = []

		// Build track based on track number
		switch (track) {
			case 1: // Speed Circuit - Fast track with long straights
				this.addStraight(ROAD.LENGTH.LONG)
				this.addCurve(ROAD.LENGTH.SHORT, ROAD.CURVE.EASY, ROAD.HILL.NONE)
				this.addStraight(ROAD.LENGTH.LONG * 2)
				this.addCurve(ROAD.LENGTH.SHORT, -ROAD.CURVE.EASY, ROAD.HILL.NONE)
				this.addStraight(ROAD.LENGTH.LONG)
				this.addHill(ROAD.LENGTH.MEDIUM, ROAD.HILL.LOW)
				this.addStraight(ROAD.LENGTH.LONG)
				this.addCurve(ROAD.LENGTH.MEDIUM, ROAD.CURVE.MEDIUM, ROAD.HILL.NONE)
				this.addStraight(ROAD.LENGTH.LONG * 2)
				this.addCurve(ROAD.LENGTH.SHORT, -ROAD.CURVE.HARD, ROAD.HILL.NONE)
				this.addStraight(ROAD.LENGTH.MEDIUM)
				this.addDownhillToEnd()
				break

			case 2: // Mountain Pass - Challenging hills and curves
				this.addHill(ROAD.LENGTH.SHORT, ROAD.HILL.MEDIUM)
				this.addCurve(ROAD.LENGTH.MEDIUM, ROAD.CURVE.HARD, ROAD.HILL.HIGH)
				this.addHill(ROAD.LENGTH.LONG, -ROAD.HILL.MEDIUM)
				this.addSCurves()
				this.addHill(ROAD.LENGTH.MEDIUM, ROAD.HILL.HIGH)
				this.addCurve(ROAD.LENGTH.LONG, -ROAD.CURVE.MEDIUM, -ROAD.HILL.LOW)
				this.addBumps()
				this.addHill(ROAD.LENGTH.LONG, ROAD.HILL.MEDIUM)
				this.addCurve(ROAD.LENGTH.MEDIUM, ROAD.CURVE.EASY, -ROAD.HILL.HIGH)
				this.addSCurves()
				this.addHill(ROAD.LENGTH.SHORT, -ROAD.HILL.MEDIUM)
				this.addDownhillToEnd()
				break

			case 3: // Technical Circuit - Lots of curves
				this.addStraight(ROAD.LENGTH.SHORT)
				this.addSCurves()
				this.addCurve(ROAD.LENGTH.MEDIUM, ROAD.CURVE.HARD, ROAD.HILL.NONE)
				this.addCurve(ROAD.LENGTH.MEDIUM, -ROAD.CURVE.HARD, ROAD.HILL.NONE)
				this.addSCurves()
				this.addCurve(ROAD.LENGTH.SHORT, ROAD.CURVE.EASY, ROAD.HILL.LOW)
				this.addCurve(ROAD.LENGTH.SHORT, -ROAD.CURVE.EASY, -ROAD.HILL.LOW)
				this.addBumps()
				this.addSCurves()
				this.addCurve(ROAD.LENGTH.LONG, ROAD.CURVE.MEDIUM, ROAD.HILL.MEDIUM)
				this.addStraight(ROAD.LENGTH.SHORT)
				this.addSCurves()
				this.addDownhillToEnd()
				break

			default: // Track 0 - Original balanced track
				this.addStraight(ROAD.LENGTH.SHORT)
				this.addLowRollingHills()
				this.addSCurves()
				this.addCurve(ROAD.LENGTH.MEDIUM, ROAD.CURVE.MEDIUM, ROAD.HILL.LOW)
				this.addBumps()
				this.addLowRollingHills()
				this.addCurve(ROAD.LENGTH.LONG * 2, ROAD.CURVE.MEDIUM, ROAD.HILL.MEDIUM)
				this.addStraight()
				this.addHill(ROAD.LENGTH.MEDIUM, ROAD.HILL.HIGH)
				this.addSCurves()
				this.addCurve(ROAD.LENGTH.LONG, -ROAD.CURVE.MEDIUM, ROAD.HILL.NONE)
				this.addHill(ROAD.LENGTH.LONG, ROAD.HILL.HIGH)
				this.addCurve(ROAD.LENGTH.LONG, ROAD.CURVE.MEDIUM, -ROAD.HILL.LOW)
				this.addBumps()
				this.addHill(ROAD.LENGTH.LONG, -ROAD.HILL.MEDIUM)
				this.addStraight()
				this.addSCurves()
				this.addDownhillToEnd()
		}

		this.resetSprites()

		// Mark start and finish lines
		const playerSegment = this.findSegment(playerZ)
		this.segments[playerSegment.index + 2].color = COLORS.START
		this.segments[playerSegment.index + 3].color = COLORS.START

		for (let n = 0; n < this.rumbleLength; n++) {
			this.segments[this.segments.length - 1 - n].color = COLORS.FINISH
		}

		this.trackLength = this.segments.length * this.segmentLength
	}

	/**
	 * Reset sprites on the track
	 */
	private resetSprites(): void {
		// Clear billboard tracking
		this.billboardPlacements.clear()
		this.billboardImpressions.clear()
		this.billboardInstances.clear()
		this.nextBillboardId = 0

		// Add billboards and plants randomly
		for (let n = 20; n < this.segments.length - 50; n += 60) {
			const billboard = MathUtils.randomChoice([...SPRITES.BILLBOARDS])
			const billboardName = this.getBillboardName(billboard)

			// Track billboard placement
			if (billboardName) {
				const current = this.billboardPlacements.get(billboardName) || 0
				this.billboardPlacements.set(billboardName, current + 1)
			}

			this.addSprite(
				n + MathUtils.randomInt(0, 50),
				billboard,
				MathUtils.randomChoice([1, -1, 1.1, -1.1, 1.2, -1.2])
			)

			for (let i = 0; i < 20; i++) {
				this.addSprite(
					n + MathUtils.randomInt(0, 50),
					MathUtils.randomChoice([...SPRITES.PLANTS]),
					MathUtils.randomChoice([1.1, -1.1]) * (1 + Math.random())
				)
			}
		}

		// Add plants along the track
		for (let n = 10; n < this.segments.length; n += 3 + Math.floor(n / 100)) {
			this.addSprite(
				n,
				MathUtils.randomChoice([...SPRITES.PLANTS]),
				MathUtils.randomChoice([1, -1]) * (1 + Math.random() * 5)
			)
		}

		// Add columns randomly
		for (let n = 120; n < this.segments.length; n += 30 + Math.floor(n / 20)) {
			this.addSprite(
				n,
				SPRITES.COLUMN,
				MathUtils.randomChoice([1, -1]) * (1 + Math.random() * 5)
			)
		}

		// Add coins in lanes
		const LANE_POSITIONS = [-0.5, 0, 0.5]
		for (let n = 0; n < this.segments.length; n += 30) {
			this.addSprite(n, SPRITES.COIN, MathUtils.randomChoice(LANE_POSITIONS))
		}
	}

	/**
	 * Remove all coins from the track
	 */
	removeAllCoins(): void {
		for (const segment of this.segments) {
			segment.sprites = segment.sprites.filter(
				sprite => sprite.source !== SPRITES.COIN
			)
		}
	}

	/**
	 * Reset cars on the track
	 */
	resetCars(totalCars: number, maxSpeed: number): Car[] {
		// Clear existing cars from segments
		for (const segment of this.segments) {
			segment.cars = []
		}

		const cars: Car[] = []

		for (let n = 0; n < totalCars; n++) {
			const offset = Math.random() * MathUtils.randomChoice([-0.8, 0.8])
			const z =
				Math.floor(Math.random() * this.segments.length) * this.segmentLength
			const sprite = MathUtils.randomChoice([...SPRITES.CARS])
			const speed =
				maxSpeed / 4 +
				(Math.random() * maxSpeed) / (sprite === SPRITES.SEMI ? 4 : 2)

			const car: Car = {
				offset,
				z,
				sprite,
				speed,
				percent: MathUtils.percentRemaining(z, this.segmentLength),
			}
			const segment = this.findSegment(car.z)
			segment.cars.push(car)
			cars.push(car)
		}

		return cars
	}

	/**
	 * Get billboard name from sprite object
	 */
	getBillboardName(sprite: Sprite): string | null {
		// Check each billboard sprite to find which one matches
		if (sprite === SPRITES.BILLBOARD01) return 'BILLBOARD01'
		if (sprite === SPRITES.BILLBOARD02) return 'BILLBOARD02'
		if (sprite === SPRITES.BILLBOARD03) return 'BILLBOARD03'
		if (sprite === SPRITES.BILLBOARD04) return 'BILLBOARD04'
		if (sprite === SPRITES.BILLBOARD05) return 'BILLBOARD05'
		if (sprite === SPRITES.BILLBOARD06) return 'BILLBOARD06'
		if (sprite === SPRITES.BILLBOARD07) return 'BILLBOARD07'
		if (sprite === SPRITES.BILLBOARD08) return 'BILLBOARD08'
		if (sprite === SPRITES.BILLBOARD09) return 'BILLBOARD09'
		return null
	}
}
